private val LoginBlue = AppColors.PrimaryBlue
private val FacebookBlue = Color(0xFF1877F2)
private val GoogleRed = Color(0xFFDB4437)

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun LoginScreen(
    navController: NavController,
    returnRoute: String = "home",
    viewModel: LoginViewModel = hiltViewModel()
) {
    // [1] Check 1 lần khi vào màn hình: nếu đã đăng nhập rồi → navigate đi luôn
    LaunchedEffect(Unit) {
        viewModel.clearError()
        val alreadyLoggedIn = viewModel.isLoggedIn.first()
        if (alreadyLoggedIn) {
            navController.navigate(returnRoute) {
                popUpTo("login/{returnRoute}") { inclusive = true }
            }
        }
    }

    // [2] Sau khi bấm Đăng nhập thành công → navigate về returnRoute (dùng Channel event, không bao giờ miss)
    LaunchedEffect(Unit) {
        viewModel.loginSuccess.collectLatest {
            navController.navigate(returnRoute) {
                popUpTo("login/{returnRoute}") { inclusive = true }
            }
        }
    }

    Scaffold(
        topBar = {
            TopAppBar(
                title = { Text("Đăng nhập", color = Color.White, fontWeight = FontWeight.Bold) },
                navigationIcon = {
                    IconButton(onClick = { navController.popBackStack() }) {
                        Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Quay lại", tint = Color.White)
                    }
                },
                colors = TopAppBarDefaults.topAppBarColors(containerColor = LoginBlue)
            )
        },
        containerColor = Color.White
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
                .padding(horizontal = 24.dp)
                .verticalScroll(rememberScrollState()),
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            Spacer(Modifier.height(32.dp))

            // ---- Logo + Slogan ----
            Text(
                "BOOKVERSE",
                color = LoginBlue,
                fontWeight = FontWeight.ExtraBold,
                fontSize = 26.sp,
                letterSpacing = 2.sp
            )
            Spacer(Modifier.height(6.dp))
            Text(
                "Khám phá thế giới qua từng trang sách",
                color = Color.Gray,
                fontSize = 13.sp,
                fontStyle = FontStyle.Italic
            )

            Spacer(Modifier.height(36.dp))

            // ---- Tên đăng nhập ----
            Column(modifier = Modifier.fillMaxWidth()) {
                Text("Tên đăng nhập", fontWeight = FontWeight.Medium, fontSize = 14.sp)
                Spacer(Modifier.height(6.dp))
                OutlinedTextField(
                    value = viewModel.loginUsername,
                    onValueChange = { viewModel.loginUsername = it; viewModel.clearError() },
                    placeholder = { Text("Nhập tên đăng nhập", color = Color.LightGray) },
                    leadingIcon = { Icon(Icons.Default.Email, contentDescription = null, tint = Color.Gray) },
                    modifier = Modifier.fillMaxWidth(),
                    shape = RoundedCornerShape(10.dp),
                    singleLine = true,
                    keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Text),
                    colors = OutlinedTextFieldDefaults.colors(
                        focusedBorderColor = LoginBlue,
                        unfocusedBorderColor = Color(0xFFDDDDDD)
                    )
                )
            }

            Spacer(Modifier.height(16.dp))

            // ---- Mật khẩu ----
            Column(modifier = Modifier.fillMaxWidth()) {
                Text("Mật khẩu", fontWeight = FontWeight.Medium, fontSize = 14.sp)
                Spacer(Modifier.height(6.dp))
                OutlinedTextField(
                    value = viewModel.loginPassword,
                    onValueChange = { viewModel.loginPassword = it; viewModel.clearError() },
                    placeholder = { Text("Nhập mật khẩu", color = Color.LightGray) },
                    leadingIcon = { Icon(Icons.Default.Lock, contentDescription = null, tint = Color.Gray) },
                    trailingIcon = {
                        IconButton(onClick = { viewModel.loginPasswordVisible = !viewModel.loginPasswordVisible }) {
                            Icon(
                                if (viewModel.loginPasswordVisible) Icons.Default.Visibility
                                else Icons.Default.VisibilityOff,
                                contentDescription = null,
                                tint = Color.Gray
                            )
                        }
                    },
                    visualTransformation = if (viewModel.loginPasswordVisible) VisualTransformation.None
                                           else PasswordVisualTransformation(),
                    modifier = Modifier.fillMaxWidth(),
                    shape = RoundedCornerShape(10.dp),
                    singleLine = true,
                    keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Password),
                    colors = OutlinedTextFieldDefaults.colors(
                        focusedBorderColor = LoginBlue,
                        unfocusedBorderColor = Color(0xFFDDDDDD)
                    )
                )
            }

            Spacer(Modifier.height(12.dp))

            // ---- Ghi nhớ + Quên mật khẩu ----
            Row(
                modifier = Modifier.fillMaxWidth(),
                verticalAlignment = Alignment.CenterVertically,
                horizontalArrangement = Arrangement.SpaceBetween
            ) {
                Row(verticalAlignment = Alignment.CenterVertically) {
                    Checkbox(
                        checked = viewModel.rememberMe,
                        onCheckedChange = { viewModel.rememberMe = it },
                        colors = CheckboxDefaults.colors(checkedColor = LoginBlue)
                    )
                    Text("Ghi nhớ mật khẩu", fontSize = 13.sp)
                }
                TextButton(onClick = { /* TODO: quên mật khẩu */ }) {
                    Text("Quên mật khẩu?", color = LoginBlue, fontSize = 13.sp)
                }
            }

            Spacer(Modifier.height(8.dp))

            // ---- Thông báo lỗi ----
            if (viewModel.errorMessage != null) {
                Text(
                    text = viewModel.errorMessage!!,
                    color = Color.Red,
                    fontSize = 13.sp,
                    modifier = Modifier.fillMaxWidth()
                )
                Spacer(Modifier.height(8.dp))
            }

            // ---- Nút Đăng nhập ----
            Button(
                onClick = {
                    viewModel.login {}
                },
                enabled = !viewModel.isLoading,
                modifier = Modifier
                    .fillMaxWidth()
                    .height(52.dp),
                shape = RoundedCornerShape(12.dp),
                colors = ButtonDefaults.buttonColors(containerColor = LoginBlue)
            ) {
                if (viewModel.isLoading) {
                    CircularProgressIndicator(color = Color.White, modifier = Modifier.size(22.dp), strokeWidth = 2.dp)
                    Spacer(Modifier.width(10.dp))
                    Text("Đang kết nối...", color = Color.White, fontSize = 14.sp)
                } else {
                    Text("Đăng nhập", color = Color.White, fontWeight = FontWeight.Bold, fontSize = 16.sp)
                }
            }

            Spacer(Modifier.height(24.dp))

            // ---- Divider "Hoặc đăng nhập bằng" ----
            Row(
                modifier = Modifier.fillMaxWidth(),
                verticalAlignment = Alignment.CenterVertically
            ) {
                HorizontalDivider(modifier = Modifier.weight(1f), color = Color(0xFFDDDDDD))
                Text(
                    "  Hoặc đăng nhập bằng  ",
                    color = Color.Gray,
                    fontSize = 12.sp
                )
                HorizontalDivider(modifier = Modifier.weight(1f), color = Color(0xFFDDDDDD))
            }

            Spacer(Modifier.height(20.dp))

            // ---- Facebook + Google ----
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(12.dp)
            ) {
                // Facebook
                OutlinedButton(
                    onClick = { /* TODO: Facebook login */ },
                    modifier = Modifier
                        .weight(1f)
                        .height(48.dp),
                    shape = RoundedCornerShape(10.dp),
                    border = BorderStroke(0.dp, Color.Transparent),
                    colors = ButtonDefaults.outlinedButtonColors(
                        containerColor = FacebookBlue,
                        contentColor = Color.White
                    )
                ) {
                    Text("f", fontWeight = FontWeight.ExtraBold, fontSize = 15.sp)
                    Spacer(Modifier.width(6.dp))
                    Text("Đăng nhập với facebook", fontSize = 12.sp, maxLines = 1)
                }

                // Google
                OutlinedButton(
                    onClick = { /* TODO: Google login */ },
                    modifier = Modifier
                        .weight(1f)
                        .height(48.dp),
                    shape = RoundedCornerShape(10.dp),
                    border = BorderStroke(0.dp, Color.Transparent),
                    colors = ButtonDefaults.outlinedButtonColors(
                        containerColor = GoogleRed,
                        contentColor = Color.White
                    )
                ) {
                    Text("G", fontWeight = FontWeight.ExtraBold, fontSize = 15.sp)
                    Spacer(Modifier.width(6.dp))
                    Text("Đăng nhập với google", fontSize = 12.sp, maxLines = 1)
                }
            }

            Spacer(Modifier.height(28.dp))

            // ---- Đăng ký ----
            Row(
                horizontalArrangement = Arrangement.Center,
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text("Bạn chưa có tài khoản?", fontSize = 14.sp, color = Color.Gray)
                TextButton(onClick = { navController.navigate("register") }) {
                    Text("Đăng kí ngay", color = LoginBlue, fontWeight = FontWeight.Bold, fontSize = 14.sp)
                }
            }

            Spacer(Modifier.height(24.dp))
        }
    }
}

